+    let detector = MockWindowDetector::with_sequence(windows);
+    let idle = MockIdleDetector::with_idle_seconds(0);
+    let config = activtrak::config::TrackerConfig::default();
+
+    let mut tracker =
+        AsyncTracker::new_with_mocks(conn, Box::new(detector), Box::new(idle), config);
+
+    tracker.poll_once().await.unwrap();
+    tracker.poll_once().await.unwrap();
+    tracker.poll_once().await.unwrap();
+
+    let count: i64 = tracker
+        .conn()
+        .query_row("SELECT COUNT(*) FROM activity_log", [], |row| row.get(0))
+        .unwrap();
+    assert_eq!(count, 2, "AppA -> AppB -> AppA should flush two records");
+
+    let switch_count: i64 = tracker
+        .conn()
+        .query_row(
+            "SELECT COUNT(*) FROM activity_log WHERE is_context_switch = 1",
+            [],
+            |row| row.get(0),
+        )
+        .unwrap();
+    assert_eq!(
+        switch_count, 2,
+        "returning to a prior app should still count both transitions as context switches"
+    );
+}

