+    let mut counter = SwitchCounter::new();
+    let window_start = Utc.with_ymd_and_hms(2026, 1, 1, 23, 30, 0).unwrap();
+    let window_end = Utc.with_ymd_and_hms(2026, 1, 2, 0, 30, 0).unwrap();
+
+    counter.record_switch(Utc.with_ymd_and_hms(2026, 1, 1, 23, 45, 0).unwrap());
+    counter.record_switch(Utc.with_ymd_and_hms(2026, 1, 2, 0, 15, 0).unwrap());
+
+    let rate = counter.switches_per_hour(window_start, window_end);
+    assert!(
+        (rate - 2.0).abs() < 0.001,
+        "2 switches across midnight in a 1-hour window should give 2.0/hr, got {rate}"
+    );
+}
+
+#[test]
+fn switches_per_hour_SwitchAtWindowStart_IsCounted() {
+    let mut counter = SwitchCounter::new();
+    let window_start = Utc.with_ymd_and_hms(2026, 1, 1, 9, 0, 0).unwrap();
+    let window_end = Utc.with_ymd_and_hms(2026, 1, 1, 9, 30, 0).unwrap();
+
+    counter.record_switch(window_start);
